settings.custom_liquid:
{% assign image_url = 'https://cdn.shopify.com/s/files/1/0796/9528/2482/files/Carbolance_Logo_Type_Black.svg?v=1696940555' %}
{% assign image_alt = 'Carbolance logo type black' %}
{% assign image_link = '#' %}

<section class="image-banner">
  <a href="{{ image_link }}">
    <object data="{{ image_url }}" alt="{{ image_alt }}" type="image/svg+xml" class="image-banner__image">
      <img src="{{ image_url }}" alt="{{ image_alt }}" class="image-banner__fallback">
    </object>
  </a>
</section>

<style>
  .image-banner {
    width: 100%;
    height: auto;
    background-color: #ffffff;
    padding: 0.5rem;
    text-align: center;
  }

  .image-banner__image {
    width: 240px; /* Set desired image width */
    height: auto;
    margin: 0 auto; /* Center image horizontally */
  }

  .image-banner__fallback {
    display: none;
  }
</style>
